// n8n Code Node

// Initialize an empty object to store the aggregated results
const aggregatedDict = {};

// Get all input items passed to this node
const inputItems = $input.all();

// Loop through each input item
for (const item of inputItems) {
  // Get the JSON data from the current item
  const itemJson = item.json;

  // Check if item.json is actually an object and not null/undefined
  // Also ensure it's not an array, as we expect key-value pairs
  if (itemJson && typeof itemJson === 'object' && !Array.isArray(itemJson)) {

    // Iterate over all the keys within the current item's JSON object
    for (const key of Object.keys(itemJson)) {
      // Add/overwrite the key-value pair to our aggregated dictionary
      aggregatedDict[key] = itemJson[key].replaceAll(/\n+/g, "\n");
      // console.log(`Adding/Updating key: ${key}`); // Optional: for debugging
    }

  } else {
    // Optional: Log a warning if an item doesn't have the expected format
    console.warn(`Skipping item - 'json' property is not a valid object:`, itemJson);
  }
}

// n8n expects an array of items as output.
// We return a single item containing the final aggregated dictionary in its 'json' property.
return [{ json: aggregatedDict }];
